<script setup>
import{computed,onMounted,reactive,ref}from'vue';import AppIcon from'../components/AppIcon.vue';import{adminApi,authToken,get,post}from'../services/http';
const tab=ref('templates'),templates=ref([]),codes=ref([]),usages=ref([]),types=ref({1:'通用礼品卡',2:'套餐礼品卡',3:'盲盒礼品卡'}),stats=ref({}),loading=ref(false),saving=ref(false),busy=ref(null),showTemplate=ref(false),showGenerate=ref(false);const toast=reactive({text:'',type:'success'}),tf=reactive(templateForm()),gf=reactive({template_id:'',count:10,prefix:'GC',expires_hours:720,max_usage:1,download:true}),codeFilter=reactive({template_id:'',status:'all',batch_id:''}),usageFilter=reactive({template_id:'',user_id:''}),pages=reactive({templates:{page:1,total:0,last:1},codes:{page:1,total:0,last:1},usages:{page:1,total:0,last:1}});
function templateForm(){return{id:null,name:'',description:'',type:1,status:true,rewards_text:'{\n  "balance": 1000\n}',conditions_text:'{}',limits_text:'{}',special_config_text:'{}',icon:'Gift',background_image:'',theme_color:'#1890ff',sort:0}}function notify(text,type='success'){toast.text=text;toast.type=type;clearTimeout(notify.timer);notify.timer=setTimeout(()=>toast.text='',2800)}function normalize(data,key){const s=data?.data??data,list=s?.items||s?.data||(Array.isArray(s)?s:[]);pages[key].total=Number(s?.total||list.length);pages[key].page=Number(s?.current_page||s?.current||pages[key].page);pages[key].last=Number(s?.last_page||Math.max(1,Math.ceil(pages[key].total/15)));return list}function qs(obj){const q=new URLSearchParams();Object.entries(obj).forEach(([k,v])=>v!==''&&v!=='all'&&v!=null&&q.set(k,String(v)));return q.toString()}function jsonText(v){return JSON.stringify(v||{},null,2)}function time(v){return v?new Date(Number(v)*1000).toLocaleString('zh-CN',{hour12:false}):'长期有效'}function statusClass(v){return Number(v)===0?'':Number(v)===3||Number(v)===2?'off':'waiting'}
async function loadStats(){try{const d=await get('/gift-card/statistics');stats.value=d?.total_stats||{}}catch(e){notify(e.message,'error')}}async function loadTemplates(reset=false){if(reset)pages.templates.page=1;loading.value=true;try{templates.value=normalize(await get('/gift-card/templates',{page:pages.templates.page,per_page:15}),'templates')}catch(e){notify(e.message,'error')}finally{loading.value=false}}async function loadCodes(reset=false){if(reset)pages.codes.page=1;loading.value=true;try{codes.value=normalize(await get(`/gift-card/codes?${qs({page:pages.codes.page,per_page:15,...codeFilter})}`),'codes')}catch(e){notify(e.message,'error')}finally{loading.value=false}}async function loadUsages(reset=false){if(reset)pages.usages.page=1;loading.value=true;try{usages.value=normalize(await get(`/gift-card/usages?${qs({page:pages.usages.page,per_page:15,...usageFilter})}`),'usages')}catch(e){notify(e.message,'error')}finally{loading.value=false}}async function switchTab(v){tab.value=v;if(v==='templates')await loadTemplates();if(v==='codes')await loadCodes();if(v==='usages')await loadUsages()}
function createTemplate(){Object.assign(tf,templateForm());showTemplate.value=true}function editTemplate(t){Object.assign(tf,templateForm(),t,{rewards_text:jsonText(t.rewards),conditions_text:jsonText(t.conditions),limits_text:jsonText(t.limits),special_config_text:jsonText(t.special_config)});showTemplate.value=true}function parseObject(text,label,required=false){let v;try{v=JSON.parse(text||'{}')}catch{throw new Error(`${label} JSON 格式不正确`)}if(!v||Array.isArray(v)||typeof v!=='object'||(required&&!Object.keys(v).length))throw new Error(`${label}必须是${required?'非空':''} JSON 对象`);return v}async function saveTemplate(){saving.value=true;try{const payload={id:tf.id||undefined,name:tf.name.trim(),description:tf.description||null,type:Number(tf.type),status:Boolean(tf.status),rewards:parseObject(tf.rewards_text,'奖励配置',true),conditions:parseObject(tf.conditions_text,'使用条件'),limits:parseObject(tf.limits_text,'使用限制'),special_config:parseObject(tf.special_config_text,'特殊配置'),icon:tf.icon||null,background_image:tf.background_image||null,theme_color:tf.theme_color,sort:Number(tf.sort||0)};if(!payload.name)throw new Error('请输入模板名称');await post(tf.id?'/gift-card/update-template':'/gift-card/create-template',payload);notify(tf.id?'模板已更新':'模板已创建');showTemplate.value=false;await Promise.all([loadTemplates(true),loadStats()])}catch(e){notify(e.message,'error')}finally{saving.value=false}}async function toggleTemplate(t){busy.value=`t${t.id}`;try{await post('/gift-card/update-template',{id:t.id,status:!t.status});t.status=!t.status;notify('模板状态已更新')}catch(e){notify(e.message,'error')}finally{busy.value=null}}async function removeTemplate(t){if(!confirm(`确定删除模板「${t.name}」？存在关联卡密时后端会阻止删除。`))return;busy.value=`t${t.id}`;try{await post('/gift-card/delete-template',{id:t.id});notify('模板已删除');await loadTemplates()}catch(e){notify(e.message,'error')}finally{busy.value=null}}
function startGenerate(t=null){Object.assign(gf,{template_id:t?.id||templates.value.find(x=>x.status)?.id||'',count:10,prefix:'GC',expires_hours:720,max_usage:1,download:true});showGenerate.value=true}async function downloadBatch(batch){const res=await fetch(`${adminApi('/gift-card/export-codes')}?batch_id=${encodeURIComponent(batch)}`,{headers:{Authorization:`Bearer ${authToken().replace(/^Bearer /,'')}`}});if(!res.ok)throw new Error('导出失败');const blob=await res.blob(),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`gift_cards_${batch}.txt`;a.click();URL.revokeObjectURL(url)}async function generate(){if(!gf.template_id)return notify('请选择礼品卡模板','error');if(Number(gf.count)<1||Number(gf.count)>10000)return notify('生成数量必须在 1–10000 之间','error');if(!/^[A-Z0-9]*$/.test(gf.prefix))return notify('前缀只能包含大写字母和数字','error');saving.value=true;try{const d=await post('/gift-card/generate-codes',{template_id:gf.template_id,count:Number(gf.count),prefix:gf.prefix,expires_hours:gf.expires_hours||undefined,max_usage:Number(gf.max_usage)});if(gf.download&&d?.batch_id)await downloadBatch(d.batch_id);notify(`已生成 ${d?.count||gf.count} 个兑换码`);showGenerate.value=false;codeFilter.batch_id=d?.batch_id||'';tab.value='codes';await Promise.all([loadCodes(true),loadStats()])}catch(e){notify(e.message,'error')}finally{saving.value=false}}
async function copyCode(v){await navigator.clipboard.writeText(v);notify('兑换码已复制')}async function toggleCode(c){const enable=Number(c.status)===3;busy.value=`c${c.id}`;try{await post('/gift-card/toggle-code',{id:c.id,action:enable?'enable':'disable'});notify(enable?'兑换码已启用':'兑换码已禁用');await loadCodes()}catch(e){notify(e.message,'error')}finally{busy.value=null}}async function removeCode(c){if(Number(c.status)===1)return notify('已使用的兑换码不能删除','error');if(!confirm(`确定删除兑换码 ${c.code}？`))return;busy.value=`c${c.id}`;try{await post('/gift-card/delete-code',{id:c.id});notify('兑换码已删除');await loadCodes()}catch(e){notify(e.message,'error')}finally{busy.value=null}}function rewardSummary(v){const r=v||{};return Object.entries(r).slice(0,4).map(([k,x])=>`${k}: ${typeof x==='object'?'…':x}`).join(' · ')||'未配置'}
onMounted(async()=>{try{types.value=await get('/gift-card/types')}catch{}await Promise.all([loadTemplates(true),loadStats()])});
</script>
<template><section class="page-stack"><div class="page-heading page-heading-row"><div><h1>礼品卡管理</h1><p>管理奖励模板、批量生成兑换码，并审计兑换使用记录。</p></div><div class="settings-actions"><button class="btn btn-ghost" @click="startGenerate()"><AppIcon name="KeyRound" :size="16"/>生成卡密</button><button class="btn btn-primary" @click="createTemplate"><AppIcon name="Plus" :size="16"/>创建模板</button></div></div><div class="stat-grid gift-stats"><article class="stat-card"><span>模板总数</span><strong>{{stats.templates_count||0}}</strong></article><article class="stat-card"><span>启用模板</span><strong>{{stats.active_templates_count||0}}</strong></article><article class="stat-card"><span>兑换码总数</span><strong>{{stats.codes_count||0}}</strong></article><article class="stat-card"><span>已使用卡密</span><strong>{{stats.used_codes_count||0}}</strong></article><article class="stat-card"><span>兑换次数</span><strong>{{stats.usages_count||0}}</strong></article></div><div class="gift-tabs"><button :class="{active:tab==='templates'}" @click="switchTab('templates')">奖励模板</button><button :class="{active:tab==='codes'}" @click="switchTab('codes')">兑换码</button><button :class="{active:tab==='usages'}" @click="switchTab('usages')">使用记录</button></div>
<template v-if="tab==='templates'"><div v-if="loading" class="panel settings-loading">正在加载模板…</div><div v-else-if="!templates.length" class="panel settings-loading">暂无礼品卡模板</div><div v-else class="gift-template-grid"><article v-for="t in templates" :key="t.id" class="panel gift-template-card" :style="{'--gift-color':t.theme_color||'#1890ff'}"><div class="gift-template-head"><span class="gift-icon">{{t.icon||'🎁'}}</span><div><small>{{t.type_name||types[t.type]}}</small><h2>{{t.name}}</h2></div><span class="status-pill" :class="{off:!t.status}">{{t.status?'启用':'停用'}}</span></div><p>{{t.description||'暂无模板说明'}}</p><div class="gift-reward"><small>奖励配置</small><code>{{rewardSummary(t.rewards)}}</code></div><div class="gift-template-meta"><span>排序 #{{t.sort||0}}</span><span>创建于 {{time(t.created_at)}}</span></div><div class="coupon-actions"><button class="btn btn-ghost btn-sm" @click="startGenerate(t)">生成卡密</button><button class="btn btn-ghost btn-sm" :disabled="busy===`t${t.id}`" @click="toggleTemplate(t)">{{t.status?'停用':'启用'}}</button><button class="btn btn-ghost btn-sm" @click="editTemplate(t)">编辑</button><button class="btn btn-danger btn-sm" :disabled="busy===`t${t.id}`" @click="removeTemplate(t)">删除</button></div></article></div></template>
<template v-if="tab==='codes'"><div class="gift-toolbar"><label class="field compact-field"><span>模板</span><select v-model="codeFilter.template_id" @change="loadCodes(true)"><option value="">全部模板</option><option v-for="t in templates" :key="t.id" :value="t.id">{{t.name}}</option></select></label><label class="field compact-field"><span>状态</span><select v-model="codeFilter.status" @change="loadCodes(true)"><option value="all">全部状态</option><option value="0">未使用</option><option value="1">已使用</option><option value="2">已过期</option><option value="3">已禁用</option></select></label><label class="filter-input"><span>批次号</span><input v-model.trim="codeFilter.batch_id" placeholder="batch_..." @keyup.enter="loadCodes(true)"/></label><button class="btn btn-ghost" @click="loadCodes(true)">查询</button><button class="btn btn-primary" @click="startGenerate()">生成卡密</button></div><div class="panel table-wrap gift-table"><table><thead><tr><th>兑换码</th><th>模板 / 批次</th><th>状态</th><th>使用次数</th><th>有效期</th><th>使用用户</th><th class="right">操作</th></tr></thead><tbody><tr v-if="loading"><td colspan="7" class="empty">正在加载兑换码…</td></tr><tr v-else-if="!codes.length"><td colspan="7" class="empty">暂无兑换码</td></tr><tr v-for="c in codes" :key="c.id"><td><button class="link-btn" @click="copyCode(c.code)">{{c.code}}</button><small>#{{c.id}}</small></td><td>{{c.template?.name||c.template_name||`模板 #${c.template_id}`}}<small>{{c.batch_id}}</small></td><td><span class="status-pill" :class="statusClass(c.status)">{{c.status_name||['未使用','已使用','已过期','已禁用'][c.status]}}</span></td><td>{{c.usage_count||0}} / {{c.max_usage}}</td><td>{{time(c.expires_at)}}</td><td>{{c.user?.email||c.user_email||'-'}}</td><td class="actions"><button v-if="[0,3].includes(Number(c.status))" class="btn btn-ghost btn-sm" :disabled="busy===`c${c.id}`" @click="toggleCode(c)">{{Number(c.status)===3?'启用':'禁用'}}</button><button class="btn btn-danger btn-sm" :disabled="Number(c.status)===1||busy===`c${c.id}`" @click="removeCode(c)">删除</button></td></tr></tbody></table></div></template>
<template v-if="tab==='usages'"><div class="gift-toolbar usage"><label class="field compact-field"><span>模板</span><select v-model="usageFilter.template_id" @change="loadUsages(true)"><option value="">全部模板</option><option v-for="t in templates" :key="t.id" :value="t.id">{{t.name}}</option></select></label><label class="filter-input"><span>用户 ID</span><input v-model.trim="usageFilter.user_id" type="number" placeholder="输入用户 ID" @keyup.enter="loadUsages(true)"/></label><button class="btn btn-ghost" @click="loadUsages(true)">查询</button></div><div class="panel table-wrap gift-table"><table><thead><tr><th>兑换码</th><th>模板</th><th>使用用户</th><th>邀请用户</th><th>奖励</th><th>倍率</th><th>兑换时间</th></tr></thead><tbody><tr v-if="loading"><td colspan="7" class="empty">正在加载使用记录…</td></tr><tr v-else-if="!usages.length"><td colspan="7" class="empty">暂无使用记录</td></tr><tr v-for="u in usages" :key="u.id"><td><code>{{u.code?.code||u.code}}</code></td><td>{{u.template?.name||u.template_name}}</td><td>{{u.user?.email||u.user_email}}</td><td>{{u.invite_user_email||'-'}}</td><td><code>{{rewardSummary(u.rewards_given)}}</code></td><td>{{u.multiplier_applied||1}}×</td><td>{{time(u.created_at)}}</td></tr></tbody></table></div></template><div v-if="tab!=='templates'" class="pagination"><span>共 {{pages[tab].total}} 条</span><button class="btn btn-ghost btn-sm" :disabled="pages[tab].page<=1||loading" @click="pages[tab].page--;tab==='codes'?loadCodes():loadUsages()">上一页</button><span>{{pages[tab].page}} / {{pages[tab].last}}</span><button class="btn btn-ghost btn-sm" :disabled="pages[tab].page>=pages[tab].last||loading" @click="pages[tab].page++;tab==='codes'?loadCodes():loadUsages()">下一页</button></div>
<div v-if="showTemplate" class="modal-backdrop" @click.self="showTemplate=false"><section class="modal-card gift-modal"><div class="panel-head"><div><h2>{{tf.id?'编辑礼品卡模板':'创建礼品卡模板'}}</h2><p>奖励、条件和限制使用 JSON 对象配置。</p></div><button class="btn btn-ghost" @click="showTemplate=false">关闭</button></div><div class="smart-form"><label class="field field-wide"><span>模板名称 *</span><input v-model.trim="tf.name"/></label><label class="field"><span>模板类型 *</span><select v-model.number="tf.type"><option v-for="(n,id) in types" :key="id" :value="Number(id)">{{n}}</option></select></label><label class="field"><span>状态</span><select v-model="tf.status"><option :value="true">启用</option><option :value="false">停用</option></select></label><label class="field"><span>图标</span><input v-model.trim="tf.icon" placeholder="Gift 或 🎁"/></label><label class="field"><span>主题颜色</span><input v-model="tf.theme_color" type="color"/></label><label class="field"><span>排序</span><input v-model.number="tf.sort" type="number" min="0"/></label><label class="field field-wide"><span>模板说明</span><textarea v-model="tf.description" rows="3"/></label><label class="field field-wide"><span>背景图片 URL</span><input v-model.trim="tf.background_image" type="url"/></label></div><div class="gift-json-grid"><label><span>奖励配置 * <small>例如余额：{"balance":1000}</small></span><textarea v-model="tf.rewards_text"/></label><label><span>使用条件</span><textarea v-model="tf.conditions_text"/></label><label><span>使用限制</span><textarea v-model="tf.limits_text"/></label><label><span>特殊配置</span><textarea v-model="tf.special_config_text"/></label></div><div class="modal-actions"><button class="btn btn-ghost" @click="showTemplate=false">取消</button><button class="btn btn-primary" :disabled="saving" @click="saveTemplate">{{saving?'保存中…':'保存模板'}}</button></div></section></div>
<div v-if="showGenerate" class="modal-backdrop" @click.self="showGenerate=false"><section class="modal-card generate-modal"><div class="panel-head"><div><h2>批量生成兑换码</h2><p>单次最多 10,000 个，生成后可自动导出文本文件。</p></div><button class="btn btn-ghost" @click="showGenerate=false">关闭</button></div><div class="smart-form"><label class="field field-wide"><span>礼品卡模板 *</span><select v-model="gf.template_id"><option value="">请选择启用模板</option><option v-for="t in templates.filter(x=>x.status)" :key="t.id" :value="t.id">{{t.name}}</option></select></label><label class="field"><span>生成数量 *</span><input v-model.number="gf.count" type="number" min="1" max="10000"/></label><label class="field"><span>卡密前缀</span><input v-model.trim="gf.prefix" maxlength="10" placeholder="GC"/></label><label class="field"><span>有效期（小时）</span><input v-model.number="gf.expires_hours" type="number" min="1" placeholder="留空长期有效"/></label><label class="field"><span>最大使用次数</span><input v-model.number="gf.max_usage" type="number" min="1" max="1000"/></label><label class="gift-download"><input v-model="gf.download" type="checkbox"/>生成后自动下载兑换码 TXT</label></div><div class="modal-actions"><button class="btn btn-ghost" @click="showGenerate=false">取消</button><button class="btn btn-primary" :disabled="saving" @click="generate">{{saving?'生成中…':'生成兑换码'}}</button></div></section></div><div v-if="toast.text" class="toast" :class="{error:toast.type==='error'}">{{toast.text}}</div></section></template>
